final:
module full_adder (
    input a,
    input b,
    input cin,
    output sum,
    output cout
);

    // Full adder logic
    assign sum = a ^ b ^ cin;
  wire temp1_(a & b) = (a & b);
  wire temp2_(cin & (a ^ b)) = (cin & (a ^ b));
  assign cout = temp1_(a & b) | temp2_(cin & (a ^ b));

endmodule
